var limitOccurrences = function(nums, k) {
    const result = [];
    const counts = new Map();
    for (const v of nums) {
        const c = counts.get(v) || 0;
        if (c < k) {
            result.push(v);
            counts.set(v, c + 1);
        }
    }
    return result;
};
